import { useEffect, useRef, useState } from "react";
import { clamp, ease } from "./helpers";

export default function TrustSection() {
  const sectionRef = useRef(null);
  const [p, setP] = useState(0);

  useEffect(() => {
    const onScroll = () => {
      const el = sectionRef.current;
      if (!el) return;
      const scrolled = -el.getBoundingClientRect().top;
      const total = el.offsetHeight - window.innerHeight;
      setP(Math.max(0, Math.min(1, scrolled / (total * 0.88))));
    };
    window.addEventListener("scroll", onScroll, { passive: true });
    onScroll();
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  const lp = (start, end) => ease(clamp((p - start) / (end - start), 0, 1));

  const ghost1 = lp(0.15, 0.40);
  const ghost2 = lp(0.45, 0.70);

  const serif = "'Playfair Display', 'Georgia', serif";

  return (
    <div ref={sectionRef} style={{ height: "280vh", position: "relative", background: "#fff" }}>
      <div style={{
        position: "sticky",
        top: 0,
        height: "100vh",
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        overflow: "hidden",
        padding: "0 8vw",
      }}>

        {/* Main text container */}
        <div style={{
          position: "relative",
          textAlign: "center",
          zIndex: 2,
          maxWidth: 1200,
          margin: "0 auto",
        }}>
          {/* Trust, however is fragile. */}
          <div>
            <span style={{
              fontFamily: serif,
              fontSize: "clamp(56px, 9vw, 130px)",
              fontWeight: 900,
              color: "#1a3a6b",
              display: "block",
              lineHeight: 1.0,
              marginBottom: 8,
            }}>Trust,</span>
          </div>
          <div style={{
            display: "flex",
            alignItems: "baseline",
            justifyContent: "center",
            gap: "0.3em",
            flexWrap: "wrap",
            marginBottom: 48,
          }}>
            <span style={{
              fontFamily: serif,
              fontSize: "clamp(42px, 7vw, 100px)",
              fontWeight: 400,
              color: "#8b9bb0",
              lineHeight: 1.0,
            }}>however is</span>
            <span style={{
              fontFamily: serif,
              fontSize: "clamp(42px, 7vw, 100px)",
              fontWeight: 900,
              color: "#1a1a1a",
              lineHeight: 1.0,
            }}>fragile.</span>
          </div>

          {/* Descriptive paragraph - positioned like first ghost annotation */}
          <div style={{
            maxWidth: 480,
            margin: "0 auto 64px auto",
            textAlign: "center",
          }}>
            <p style={{
              fontSize: "clamp(15px, 1.1vw, 18px)",
              color: "#4a5b6e",
              lineHeight: 1.7,
              fontFamily: "'Inter', system-ui, sans-serif",
              margin: 0,
            }}>
              When speed and scale take priority, due diligence slips and blind spots widen. That's exactly what is happening in the gig economy today.
            </p>
          </div>

          {/* One breach line */}
          <div style={{ marginBottom: 32 }}>
            <span style={{
              fontFamily: serif,
              fontSize: "clamp(36px, 6vw, 90px)",
              fontWeight: 900,
              color: "#d93025",
            }}>One breach</span>
          </div>

          {/* Second descriptive paragraph */}
          <div style={{
            maxWidth: 520,
            margin: "0 auto 48px auto",
            textAlign: "center",
          }}>
            <p style={{
              fontSize: "clamp(15px, 1.1vw, 18px)",
              color: "#4a5b6e",
              lineHeight: 1.7,
              fontFamily: "'Inter', system-ui, sans-serif",
              margin: 0,
            }}>
              Identity swaps, impersonation, and hidden criminal histories do more than disrupt operations. They put safety, credibility, and customer trust at risk.
            </p>
          </div>

          {/* One bad experience */}
          <div style={{ marginBottom: 40 }}>
            <span style={{
              fontFamily: serif,
              fontSize: "clamp(36px, 6vw, 90px)",
              fontWeight: 900,
              color: "#d93025",
            }}>One bad experience</span>
          </div>

          {/* Footer line */}
          <div>
            <p style={{
              fontSize: "clamp(16px, 1.3vw, 22px)",
              color: "#2c3e4f",
              lineHeight: 1.5,
              fontFamily: "'Inter', system-ui, sans-serif",
              fontWeight: 500,
              margin: 0,
              maxWidth: 600,
              marginLeft: "auto",
              marginRight: "auto",
            }}>
              is all it takes to undo years of hard-earned customer confidence.
            </p>
          </div>
        </div>

        {/* Ghost annotation 1 - now positioned as decorative side note */}
        <div style={{
          position: "absolute",
          left: "5%",
          top: "25%",
          zIndex: 10,
          pointerEvents: "none",
          background: "rgba(255, 235, 230, 0.85)",
          backdropFilter: "blur(8px)",
          WebkitBackdropFilter: "blur(8px)",
          borderRadius: 16,
          padding: "20px 24px",
          width: 280,
          opacity: ghost1,
          transform: `translateY(${(1 - ghost1) * 80}px)`,
          transition: "none",
          borderLeft: "3px solid #d93025",
        }}>
          <p style={{
            fontSize: 13,
            color: "#2d3e50",
            lineHeight: 1.6,
            fontFamily: "'Inter', sans-serif",
            margin: 0,
          }}>
            When speed and scale take priority, due diligence slips and blind spots widen. That's exactly what is happening in the gig economy today.
          </p>
        </div>

        {/* Ghost annotation 2 - positioned as decorative side note */}
        <div style={{
          position: "absolute",
          right: "5%",
          bottom: "20%",
          zIndex: 10,
          pointerEvents: "none",
          background: "rgba(230, 240, 255, 0.85)",
          backdropFilter: "blur(8px)",
          WebkitBackdropFilter: "blur(8px)",
          borderRadius: 16,
          padding: "20px 24px",
          width: 300,
          opacity: ghost2,
          transform: `translateY(${(1 - ghost2) * 80}px)`,
          transition: "none",
          borderRight: "3px solid #d93025",
        }}>
          <p style={{
            fontSize: 13,
            color: "#2d3e50",
            lineHeight: 1.6,
            fontFamily: "'Inter', sans-serif",
            margin: 0,
          }}>
            Identity swaps, impersonation, and hidden criminal histories do more than disrupt operations. They put safety, credibility, and customer trust at risk.
          </p>
        </div>

      </div>
    </div>
  );
}
